import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"数据埋点治理与数据质量体系","description":"","frontmatter":{},"headers":[],"relativePath":"projects/liduoxing/tracking-governance.md","filePath":"projects/liduoxing/tracking-governance.md"}'),l={name:"projects/liduoxing/tracking-governance.md"};function i(n,t,s,o,h,p){return d(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="数据埋点治理与数据质量体系" tabindex="-1">数据埋点治理与数据质量体系 <a class="header-anchor" href="#数据埋点治理与数据质量体系" aria-label="Permalink to &quot;数据埋点治理与数据质量体系&quot;">​</a></h1><blockquote><p>数据埋点治理是利多星数据产品体系中的基础设施项目。它覆盖 APP、小程序、PC 和 H5 页面行为数据，目标是让埋点从“能查到数据”升级为 <span class="text-highlight-blue">可信、可验收、可进入 BI、可支撑用户分析</span> 的数据资产。</p></blockquote><div class="project-snapshot"><div><strong>3 端覆盖</strong><span>APP、小程序、PC / H5 行为数据</span></div><div><strong>5 阶段 SOP</strong><span>盘点、标准、检查、修复、上线监控</span></div><div><strong>7 个事件</strong><span>完成 14 天全量事件专项验数分析</span></div><div><strong>A/B/C/D 分级</strong><span>建立埋点质量准入标准</span></div></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>金融产品的用户行为数据分布在 APP、小程序、PC 和 H5 页面中。业务需要分析 VIP 页面点击、系统通知栏、案例股详情页、策略组合、直播、课程、栏目浏览等行为。</p><p>但埋点数据一旦字段不稳，就会直接影响后续分析：</p><ul><li>用户点击了哪里，但页面 URL 没洗出来。</li><li>同一个模块有多个编码，口径无法合并。</li><li>关键字段未上报，无法判断用户行为归属。</li><li>APP、小程序、PC 端字段不一致，三端不可比。</li><li>埋点用户 ID 与订单客户 ID 无法稳定关联。</li><li>原始表和宽表清洗逻辑不一致，导致看板结果不同。</li></ul><p>因此，这个项目的重点是建立 <span class="text-highlight-warm">埋点资产盘点、质量验收、问题修复和宽表治理</span> 的完整机制。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>建立跨产品、跨端口的统一埋点管理和验收流程。</li><li>对核心事件进行全量验数，识别字段缺失、ID 差异、URL 清洗、模块编码等问题。</li><li>建立 A/B/C/D 埋点质量分级，明确哪些数据能进入正式 BI。</li><li>输出宽表清洗规则，让原始行为数据能被后续 BI、标签和客户分析复用。</li><li>将埋点治理从临时排查转成长期可执行的数据质量体系。</li></ol><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>我负责埋点治理的方法论梳理、验收 SOP 设计、字段质量分析、问题清单整理和数仓协同。这个项目需要同时懂业务页面、埋点事件、SQL 验数、宽表清洗和 BI 使用场景。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我承担的工作</th></tr></thead><tbody><tr><td>资产盘点</td><td>梳理核心产品、核心事件、所属模块、端口、触发条件和关键属性</td></tr><tr><td>验收标准</td><td>设计 A/B/C/D 质量分级，明确属性完整率、空值率、趋势稳定性等标准</td></tr><tr><td>全量验数</td><td>对重点事件做 7 天 / 14 天全量 SQL 分析和 HTML 报告</td></tr><tr><td>问题定位</td><td>识别字段未上报、URL 缺失、模块编码重复、ID 映射差异等问题</td></tr><tr><td>宽表治理</td><td>输出神策宽表清洗规则、short_user_code 补全、H5 URL 字段清洗和页面类型识别</td></tr><tr><td>协同推进</td><td>将问题反馈给产品、开发、数仓和业务方，推动修复和重新验数</td></tr></tbody></table><h2 id="埋点验收-sop" tabindex="-1">埋点验收 SOP <a class="header-anchor" href="#埋点验收-sop" aria-label="Permalink to &quot;埋点验收 SOP&quot;">​</a></h2><p>我将埋点验收拆成 5 个阶段：</p><table tabindex="0"><thead><tr><th>阶段</th><th>核心动作</th><th>产出</th></tr></thead><tbody><tr><td>1. 埋点资产盘点</td><td>整理事件 ID、事件名、模块、端口、触发条件、关键属性和 Owner</td><td>埋点资产清单</td></tr><tr><td>2. 验收标准定义</td><td>按 P0/P1/P2 定义准确性、完整率、趋势稳定性要求</td><td>量化验收标准</td></tr><tr><td>3. 数据质量检查</td><td>检查 PV/UV 趋势、字段空值率、三端一致性和漏斗逻辑</td><td>数据质量报告</td></tr><tr><td>4. 问题分类修复</td><td>区分埋点未报、字段错误、清洗缺失、业务口径不明等问题</td><td>问题清单与修复计划</td></tr><tr><td>5. 看板上线监控</td><td>只有达到准入标准的事件进入 BI，并持续监控波动</td><td>质量看板和复盘机制</td></tr></tbody></table><h2 id="质量分级" tabindex="-1">质量分级 <a class="header-anchor" href="#质量分级" aria-label="Permalink to &quot;质量分级&quot;">​</a></h2><p>为了让业务明确哪些埋点可用，我设计了 A/B/C/D 分级：</p><table tabindex="0"><thead><tr><th>等级</th><th>判断标准</th><th>BI 使用方式</th></tr></thead><tbody><tr><td>A - 可用</td><td>三端一致性高，关键属性完整，趋势稳定</td><td>可进入正式 BI</td></tr><tr><td>B - 谨慎</td><td>有小问题但趋势清晰</td><td>可做趋势分析，不做精确结论</td></tr><tr><td>C - 排查</td><td>字段缺失或波动明显</td><td>只用于问题排查</td></tr><tr><td>D - 不用</td><td>关键字段严重缺失或数据不稳定</td><td>不进入 BI</td></tr></tbody></table><p>这个分级的价值，是让“数据能不能用”变成可讨论、可验收的标准，减少感觉判断。</p><h2 id="专项验数" tabindex="-1">专项验数 <a class="header-anchor" href="#专项验数" aria-label="Permalink to &quot;专项验数&quot;">​</a></h2><p>项目中对 14 天全量数据做了多个事件专项分析，覆盖系统通知栏、案例股详情页、VIP 策略组合、尊享直播汇、精彩推荐、精品课程、栏目浏览等场景。</p><table tabindex="0"><thead><tr><th>验数对象</th><th>分析重点</th><th>发现的问题 / 价值</th></tr></thead><tbody><tr><td>系统通知栏点击</td><td>PV、UV、消息类型、落地页 URL</td><td>将通知用户与 H5 落地页访问关联起来</td></tr><tr><td>案例股详情页</td><td>H5 访问、sp_id 分布、页面贡献</td><td>识别少数核心 ID 贡献主要流量</td></tr><tr><td>VIP 策略组合</td><td>策略组合点击、用户权限分布</td><td>判断核心付费用户行为</td></tr><tr><td>尊享直播汇</td><td>直播间点击、周末回放行为</td><td>发现同名直播间多 ID 和回放流量问题</td></tr><tr><td>精品课程</td><td>点击、课程 ID、父模块探索率</td><td>发现部分字段未上报问题</td></tr><tr><td>栏目浏览</td><td>column_code、column_sort</td><td>发现字段空值和双编码问题</td></tr></tbody></table><p>这些分析用于验证每个事件是否具备进入正式看板的条件，重点不在单个事件的流量展示。</p><h2 id="宽表清洗" tabindex="-1">宽表清洗 <a class="header-anchor" href="#宽表清洗" aria-label="Permalink to &quot;宽表清洗&quot;">​</a></h2><p>埋点治理的另一个重点，是让原始行为数据可以被业务稳定使用。</p><p>我输出的宽表治理思路包括：</p><ul><li><code>short_user_code</code> 补全逻辑：当用户短编码为空或异常时，用可映射字段补齐。</li><li>H5 URL 字段清洗：补充 <code>page_url</code>、<code>url_path</code>、<code>url_host</code>、<code>referrer_title</code> 等字段。</li><li>页面类型识别：从 URL 中提取页面类型、策略代码、股票代码等信息。</li><li>原始表与宽表差异复核：避免同一事件在不同表中出现不同结果。</li><li>宽表 v2 建表方案：修复 v1 宽表漏洗 H5 URL 字段的问题。</li></ul><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><p>埋点治理的数据链路是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始埋点</span></span>
<span class="line"><span>  -&gt; 字段拆解</span></span>
<span class="line"><span>  -&gt; 质量评分</span></span>
<span class="line"><span>  -&gt; 问题修复</span></span>
<span class="line"><span>  -&gt; 宽表清洗</span></span>
<span class="line"><span>  -&gt; BI / 标签 / 用户分析</span></span></code></pre></div><p>这个项目让后续的私享家 BI、用户标签、客户活跃分析和产品运营看板有了更可信的数据基础。</p><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>建立跨端埋点验收 SOP，将埋点工作从需求记录推进到质量管理。</li><li>输出 A/B/C/D 分级标准，让埋点是否可进入 BI 有明确判断依据。</li><li>完成重点事件的全量验数分析，沉淀 SQL、HTML 报告和问题清单。</li><li>发现并记录字段未上报、双编码、URL 清洗缺失、ID 体系差异等问题。</li><li>输出宽表 v2 清洗方案，为后续 BI 和用户标签提供稳定底表。</li><li>体现了 <span class="text-highlight-warm">数据产品经理对“数据可信度”的把控能力</span>。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>这个项目让我更加明确：数据产品的第一步是判断数据是否可信。只有埋点、字段、ID 和宽表稳定，业务看板、客户标签和用户分析才有意义。</p>`,36)])])}const b=a(l,[["render",i]]);export{u as __pageData,b as default};
